#include<bits/stdc++.h>
using namespace std;
vector<long long> mp[5050];
long long sum[5050],f[5050],max1,g[5050];
void dfs(long long x,long long dep=1,long long fa=-1)
{
    max1=max(max1,dep);
    sum[dep]++;
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,dep+1,x);
        }
    }
}
int main()
{
    long long n,ans=0;
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    for(long long i=1;i<=n;i++)
    {
        memset(f,0,sizeof(f));
        memset(g,0,sizeof(g));
        for(long long j:mp[i])
        {
            memset(sum,0,sizeof(sum));
            max1=0;
            dfs(j,1,i);
            for(long long k=1;k<=max1;k++)
            {
                ans+=f[k]*sum[k];
                f[k]+=g[k]*sum[k];
                g[k]+=sum[k];
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
